788	/// C: `int luaV_equalobj(lua_State *L, const TValue *t1, const TValue *t2)`
789	/// Main equality test.  `raw = true` means no metamethods (L == NULL in C).
790	pub(crate) fn equal_obj(
791	    state: Option<&mut LuaState>,
792	    t1: &LuaValue,
793	    t2: &LuaValue,
794	) -> Result<bool, LuaError> {
795	    // C: if (ttypetag(t1) != ttypetag(t2)) — different full type tags?
796	    // In Rust, same variant = same tag.  If variant differs, check the number
797	    // special case (Int and Float can be equal).
798	    let same_variant = std::mem::discriminant(t1) == std::mem::discriminant(t2);
799	    if !same_variant {
800	        // C: if (ttype(t1) != ttype(t2) || ttype(t1) != LUA_TNUMBER) return 0;
801	        let t1_is_num = matches!(t1, LuaValue::Int(_) | LuaValue::Float(_));
802	        let t2_is_num = matches!(t2, LuaValue::Int(_) | LuaValue::Float(_));
803	        if !(t1_is_num && t2_is_num) {
804	            return Ok(false);
805	        }
806	        // C: two numbers with different variants — compare via integer conversion
807	        // luaV_tointegerns(t1, &i1, F2Ieq) && luaV_tointegerns(t2, &i2, F2Ieq) && i1==i2
808	        let i1 = to_integer_ns(t1, F2Imod::Eq);
809	        let i2 = to_integer_ns(t2, F2Imod::Eq);
810	        return Ok(i1.is_some() && i2.is_some() && i1 == i2);
811	    }
812	
813	    // C: same variant — switch on type tag
814	    match (t1, t2) {
815	        (LuaValue::Nil,  LuaValue::Nil)  => Ok(true),
816	        (LuaValue::Bool(b1), LuaValue::Bool(b2)) => Ok(b1 == b2),
817	        (LuaValue::Int(i1), LuaValue::Int(i2)) => Ok(i1 == i2),
