    // types.tsv: global_State.totalbytes → isize
    pub totalbytes: isize,

    // C: l_mem GCdebt — Phase D GC pacing
    // types.tsv: global_State.GCdebt → isize
    pub gc_debt: isize,

    // C: lu_mem GCestimate — Phase D
    pub gc_estimate: usize,

